+/// Complex-aware logn (base n): returns complex result for negative inputs.
+pub fn scimath_logn(n: f64, x: &UFuncArray) -> Result<UFuncArray, UFuncError> {
+    let ln_n = n.ln();
+    scimath_unary(x, |v| {
+        if v > 0.0 {
+            (v.ln() / ln_n, 0.0)
+        } else if v == 0.0 {
+            (f64::NEG_INFINITY, 0.0)
+        } else {
+            ((-v).ln() / ln_n, std::f64::consts::PI / ln_n)
+        }
+    })
+}
